#include <stdio.h>
#include <stdbool.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; long long K; scanf("%d %lld", &N, &K);
        bool ok = false;
        for(int i=0;i<N;i++){
            long long x; scanf("%lld", &x);
            if(x==K) ok = true;
        }
        if(N==1 && !ok) printf("No\n");
        else if(N==1 && ok) printf("Yes\n");
        else if(ok) printf("Yes\n");
        else printf("No\n");
    }
    return 0;
}

