import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        n = int(next(it)); k = int(next(it))
        has_k = False
        for _ in range(n):
            if int(next(it)) == k:
                has_k = True
        if n == 1:
            out_lines.append('Yes' if has_k else 'No')
        else:
            out_lines.append('Yes' if has_k else 'No')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

